cells.content:
// Exemplo 4: Filtrar apenas logs de ERROR
fetch logs, from: now() - 1h
| filter loglevel == "ERROR"

// Exemplo 6: Usar IN para filtrar por lista
fetch logs, from: now() - 1h
| filter loglevel in ["ERROR", "WARN", "CRITICAL"]

// Exemplo 7: Excluir logs de healthcheck
fetch logs, from: now() - 1h
| filterOut contains(content, "/health") or contains(content, "/ping")

// Exemplo 8: Buscar com contains
fetch logs, from: now() - 1h
| filter contains(content, "NullPointerException")

// Exemplo 9: Buscar com matchesValue (wildcard)
fetch logs, from: now() - 1h
| filter matchesValue(dt.entity.service_name, "payment*")

// Exemplo 10: Limitar saída a 100 registros
fetch logs, from: now() - 1h
| limit 100

// Exemplo 11: Média de CPU por host, a cada 5 minutos
timeseries {
    avg_cpu = avg(dt.host.cpu.usage)
},
    interval: 5m,
    from: now() - 2h

